mapper.update:
update post
set post_likes = post_likes +1
where post_idx=#{post_idx}

mapper.select:
select *
from post
where category_idx=#{category_idx}
order by post_likes desc, post_created_at DESC
LIMIT #{offset}, #{pageSize}

SELECT p.*,
(p.post_likes * 3 + p.post_views * 1 - TIMESTAMPDIFF(DAY, p.post_created_at, NOW()) * 2
) AS popularity
FROM post p
where category_idx=#{category_idx}
ORDER BY popularity DESC
LIMIT #{offset}, #{pageSize} ;
